&#x5360;&#x7528;&#x6267;&#x884C; df -h &#x548C; du -h --max-depth=1 &#x6C47;&#x603B;&#x540E;&#x5F97;&#x5230;&#x8D44;&#x6E90;&#x4E3B;&#x8981;&#x7531;&#x4EE5;&#x4E0B;&#x5185;&#x5BB9;&#x5360;&#x7528;&#xFF1A; 1.devicemapper2.logs3.&#x5BB9;&#x5668;&#x5185;&#x65E5;&#x5FD7;4.&#x65E0;&#x7528;&#x7684; volumes &#x89E3;&#x51B3;&#x63AA;&#x65BD;&#x9488;&#x5BF9; devicemapper&#x9488;&#x5BF9; &#x5BB9;&#x5668;&#x65E5;&#x5FD7;#!/bin/bash for container_id in $(docker ps -a --filter=&quot;name=$name&quot; -q); do file=$(docker inspect $container_id | grep -G &apos;&quot;LogPath&quot;: &quot;*&quot;&apos; | sed -e &apos;s/.*&quot;LogPath&quot;: &quot;//g&apos; | sed -e &apos;s/&quot;,//g&apos;); if [ -f $file ] then echo $file; fi done &#x9488;&#x5BF9; &#x5BB9;&#x5668;&#x5185;&#x65E5;&#x5FD7;&#x65E0;&#x7528;&#x7684; volumes#! /bin/bash set -eou pipefail #usage: sudo ./docker-cleanup-volumes.sh [--dry-run] docker_bin=&quot;$(which docker.io 2&gt; /dev/null || which docker 2&gt; /dev/null)&quot; # Default dir dockerdir=/var/lib/docker # Look for an alternate docker directory with -g/--graph option dockerpid=$(ps ax | grep &quot;$docker_bin&quot; | grep -v grep | awk &apos;{print $1; exit}&apos;) || : if [[ -n &quot;$dockerpid&quot; &amp;&amp; $dockerpid -gt 0 ]]; then next_arg_is_dockerdir=false while read -d $&apos;\0&apos; arg do if [[ $arg =~ ^--graph=(.+) ]]; then dockerdir=${BASH_REMATCH[1]} break elif [ $arg = &apos;-g&apos; ]; then next_arg_is_dockerdir=true elif [ $next_arg_is_dockerdir = true ]; then dockerdir=$arg break fi done &lt; /proc/$dockerpid/cmdline fi dockerdir=$(readlink -f &quot;$dockerdir&quot;) volumesdir=${dockerdir}/volumes vfsdir=${dockerdir}/vfs/dir allvolumes=() dryrun=false verbose=false function log_verbose() { if [ &quot;${verbose}&quot; = true ]; then echo &quot;$1&quot; fi; } function delete_volumes() { local targetdir=$1 echo if [[ ! -d &quot;${targetdir}&quot; || ! &quot;$(ls -A &quot;${targetdir}&quot;)&quot; ]]; then echo &quot;Directory ${targetdir} does not exist or is empty, skipping.&quot; return fi echo &quot;Delete unused volume directories from $targetdir&quot; local dir while read -d $&apos;\0&apos; dir do dir=$(basename &quot;$dir&quot;) if [[ -d &quot;${targetdir}/${dir}/_data&quot; || &quot;${dir}&quot; =~ [0-9a-f]{64} ]]; then if [ ${#allvolumes[@]} -gt 0 ] &amp;&amp; [[ ${allvolumes[@]} =~ &quot;${dir}&quot; ]]; then echo &quot;In use ${dir}&quot; else if [ &quot;${dryrun}&quot; = false ]; then echo &quot;Deleting ${dir}&quot; rm -rf &quot;${targetdir}/${dir}&quot; else echo &quot;Would have deleted ${dir}&quot; fi fi else echo &quot;Not a volume ${dir}&quot; fi done &lt; &lt;(find &quot;${targetdir}&quot; -mindepth 1 -maxdepth 1 -type d -print0 2&gt;/dev/null) } if [ $UID != 0 ]; then echo &quot;You need to be root to use this script.&quot; exit 1 fi if [ -z &quot;$docker_bin&quot; ] ; then echo &quot;Please install docker. You can install docker by running \&quot;wget -qO- https://get.docker.io/ | sh\&quot;.&quot; exit 1 fi while [[ $# &gt; 0 ]] do key=&quot;$1&quot; case $key in -n|--dry-run) dryrun=true ;; -v|--verbose) verbose=true ;; *) echo &quot;Cleanup docker volumes: remove unused volumes.&quot; echo &quot;Usage: ${0##*/} [--dry-run] [--verbose]&quot; echo &quot; -n, --dry-run: dry run: display what would get removed.&quot; echo &quot; -v, --verbose: verbose output.&quot; exit 1 ;; esac shift done # Make sure that we can talk to docker daemon. If we cannot, we fail here. ${docker_bin} version &gt;/dev/null container_ids=$(${docker_bin} ps -a -q --no-trunc) #All volumes from all containers SAVEIFS=$IFS IFS=$(echo -en &quot;
 &quot;) for container in $container_ids; do #add container id to list of volumes, don&apos;t think these #ever exists in the volumesdir but just to be safe allvolumes+=${container} #add all volumes from this container to the list of volumes log_verbose &quot;Inspecting container ${container}&quot; for volpath in $( ${docker_bin} inspect --format=&apos;{{range $key, $val := .}}{{if eq $key &quot;Volumes&quot;}}{{range $vol, $path := .}}{{$path}}{{&quot;
&quot;}}{{end}}{{end}}{{if eq $key &quot;Mounts&quot;}}{{range $mount := $val}}{{$mount.Source}}{{&quot;
&quot;}}{{end}}{{end}}{{end}}&apos; ${container} \ ); do log_verbose &quot;Processing volumepath ${volpath}&quot; #try to get volume id from the volume path vid=$(echo &quot;${volpath}&quot; | sed &apos;s|.*/\(.*\)/_data$|\1|;s|.*/\([0-9a-f]\{64\}\)$|\1|&apos;) # check for either a 64 character vid or then end of a volumepath containing _data: if [[ &quot;${vid}&quot; =~ ^[0-9a-f]{64}$ || (${volpath} =~ .*/_data$ &amp;&amp; ! &quot;${vid}&quot; =~ &quot;/&quot;) ]]; then log_verbose &quot;Found volume ${vid}&quot; allvolumes+=(&quot;${vid}&quot;) else #check if it&apos;s a bindmount, these have a config.json file in the ${volumesdir} but no files in ${vfsdir} (docker 1.6.2 and below) for bmv in $(find &quot;${volumesdir}&quot; -name config.json -print | xargs grep -l &quot;\&quot;IsBindMount\&quot;:true&quot; | xargs grep -l &quot;\&quot;Path\&quot;:\&quot;${volpath}\&quot;&quot;); do bmv=&quot;$(basename &quot;$(dirname &quot;${bmv}&quot;)&quot;)&quot; log_verbose &quot;Found bindmount ${bmv}&quot; allvolumes+=(&quot;${bmv}&quot;) #there should be only one config for the bindmount, delete any duplicate for the same bindmount. break done fi done done IFS=$SAVEIFS delete_volumes &quot;${volumesdir}&quot; delete_volumes &quot;${vfsdir}&quot;
